          const defaultLabel = defaultEnabled ? 'الترحيل للصندوق (افتراضي)' : 'بدون ترحيل للصندوق (افتراضي)';
          const statusLabel = isRecalled ? 'تعديل تصفية' : 'تصفية جديدة';
          const saveButtonLabel = isRecalled ? 'حفظ التعديل' : 'حفظ التصفية';
      
